ORDER BY order_created_at DESC LIMIT 5;

=SELECT promo_code FROM public.promo_impressions 
WHERE chat_id = {{ $('Normalize Promo Input').first().json.chat_id }} 
AND shown_at > NOW() - INTERVAL '12 hours';

