const input = $('Normalize Promo Input').first().json;
const chatId = input.chat_id;
const currentSku = input.sku;
const cartTotal = parseFloat(input.cart_total || 0);

// Get already shown promos from DB
const sessionShownPromos = $('Get Shown Promos').all()
  .map(i => i.json.promo_code)
  .filter(Boolean);

// Get all data
const promotions = $('Get All Active Promotions').all().map(i => i.json).filter(i => i && i.promo_code);
const cartItems = $('Get Cart Items').all().map(i => i.json).filter(i => i && i.sku);
const inventory = $('Get Inventory').all().map(i => i.json).filter(i => i && i.sku);
const orderHistory = $('Get User Order History').all().map(i => i.json).filter(i => i && i.order_details_json);

// Build inventory map
const invMap = {};
inventory.forEach(p => { invMap[p.sku] = p; });

const currentProduct = invMap[currentSku] || {};
const currentCategory = currentProduct.category || '';

// Parse order history
const historicalSkus = new Set();
const historicalCategories = new Set();
orderHistory.forEach(order => {
  try {
    const details = typeof order.order_details_json === 'string'
      ? JSON.parse(order.order_details_json)
      : order.order_details_json;
    (details.items_in_final_order || []).forEach(item => {
      historicalSkus.add(item.sku);
      if (invMap[item.sku]) historicalCategories.add(invMap[item.sku].category);
    });
  } catch(e) {}
});

// Current time for time-based scoring
const now = new Date();
const currentHour = now.getHours();
const currentMonth = now.getMonth() + 1;
const seasonMap = {
  'summer': [3,4,5,6],
  'monsoon': [7,8,9],
  'winter': [11,12,1,2],
  'festive': [9,10,11]
};

// Cart skus set
const cartSkus = new Set(cartItems.map(i => i.sku));
const cartCategories = new Set(cartItems.map(i => (invMap[i.sku] || {}).category).filter(Boolean));

// Score each promotion
const scored = [];

promotions.forEach(promo => {
  // Skip if already shown in last 12 hours
  if (sessionShownPromos.includes(promo.promo_code)) return;

  // Skip if outside valid hours
  if (promo.valid_hours_start !== null && promo.valid_hours_start !== undefined &&
      promo.valid_hours_end !== null && promo.valid_hours_end !== undefined) {
    if (currentHour < promo.valid_hours_start || currentHour >= promo.valid_hours_end) return;
  }

  let score = (promo.priority || 5) * 10;
  let hintType = null;
  let hintData = {};

  // Expiry urgency
  if (promo.valid_until) {
    const hoursLeft = (new Date(promo.valid_until) - now) / (1000 * 60 * 60);
    if (hoursLeft <= 24) score += 50;
    else if (hoursLeft <= 48) score += 25;
  }

  // Seasonal match
  if (promo.seasonal_tags && promo.seasonal_tags.length > 0) {
    const matchesSeason = promo.seasonal_tags.some(tag => {
      const months = seasonMap[tag.toLowerCase()];
      return months && months.includes(currentMonth);
    });
    if (matchesSeason) score += 15;
    else score -= 20;
  }

  // BOGO nudge - user has item, needs more to trigger
  if (promo.discount_type === 'bogo' && promo.promo_scope === 'product' && promo.target_sku === currentSku) {
    const cartItem = cartItems.find(i => i.sku === currentSku);
    const currentQty = cartItem ? parseInt(cartItem.quantity) : 0;
    const needed = 3 - (currentQty % 3);
    if (needed === 1 || needed === 2) {
      score += 60;
      hintType = 'bogo_nudge';
      hintData = { needed, item_name: currentProduct.item_name, promo_code: promo.promo_code };
    }
  }

  // Direct product promo on item just added
  if (promo.promo_scope === 'product' && promo.target_sku === currentSku && promo.discount_type !== 'bogo') {
    score += 40;
    hintType = hintType || 'product_deal';
    hintData = hintType === 'product_deal' ? { promo } : hintData;
  }

  // Category promo matches item just added
  if (promo.promo_scope === 'category' && promo.target_category === currentCategory) {
    score += 30;
    hintType = hintType || 'category_deal';
    hintData = hintType === 'category_deal' ? { promo, category: currentCategory } : hintData;
  }

  // Threshold unlock - within 25% of min_cart_value
  if (promo.promo_scope === 'order' && promo.min_cart_value) {
    const threshold = parseFloat(promo.min_cart_value);
    const gap = threshold - cartTotal;
    if (gap > 0 && gap <= threshold * 0.25) {
      score += 60;
      hintType = hintType || 'threshold_unlock';
      hintData = hintType === 'threshold_unlock' ? { gap: gap.toFixed(2), promo } : hintData;
    }
  }

  // Complementary product deal
  if (promo.promo_scope === 'product' && promo.target_sku !== currentSku) {
    const targetProduct = invMap[promo.target_sku];
    if (targetProduct) {
      const currentComplements = currentProduct.complementary_skus || [];
      if (currentComplements.includes(promo.target_sku)) {
        score += 35;
        hintType = hintType || 'complementary';
        hintData = hintType === 'complementary' ? { promo, target_name: targetProduct.item_name } : hintData;
      }
    }
  }

  // History boost
  if (promo.promo_scope === 'category' && historicalCategories.has(promo.target_category)) score += 20;
  if (promo.promo_scope === 'product' && historicalSkus.has(promo.target_sku)) score += 20;

  // History-based reorder hint
  if (promo.promo_scope === 'product' && promo.target_sku !== currentSku) {
    const targetInHistory = historicalSkus.has(promo.target_sku);
    const targetNotInCart = !cartSkus.has(promo.target_sku);
    const targetProduct = invMap[promo.target_sku];
    if (targetInHistory && targetNotInCart && targetProduct) {
      score += 25;
      hintType = hintType || 'history_reorder';
      hintData = hintType === 'history_reorder' ? { promo, target_name: targetProduct.item_name } : hintData;
    }
  }

  // Low stock urgency
  if (promo.target_sku) {
    const targetProduct = invMap[promo.target_sku];
    if (targetProduct && parseInt(targetProduct.stock) <= 5 && parseInt(targetProduct.stock) > 0) {
      score += 20;
    }
  }

  if (score > 30 && hintType) {
    scored.push({ score, hintType, hintData, promo_code: promo.promo_code });
  }
});

scored.sort((a, b) => b.score - a.score);
const best = scored[0] || null;

return [{ json: { best, cartTotal, currentSku, currentProduct } }];

