function discountText(p) {
  if (!p || !p.discount_value || p.discount_value <= 0) return '';
  return p.discount_type === 'percentage'
    ? p.discount_value + '% off'
    : 'Rs.' + p.discount_value + ' off';
}

if (hintType === 'bogo_nudge') {
  hint = 'Add ' + hintData.needed + ' more ' + hintData.item_name + ' to get 1 FREE!';
}
else if (hintType === 'product_deal') {
  const p = hintData.promo;
  const dt = discountText(p);
  if (dt) {
    if (p.discount_type === 'percentage') hint = 'Deal: ' + p.promo_code + ' - ' + p.discount_value + '% off on this item!';
    else hint = 'Deal: ' + p.promo_code + ' - Rs.' + p.discount_value + ' off on this item!';
  } else {
    hint = 'Deal: ' + p.promo_code + ' applies to this item today!';
  }
}
else if (hintType === 'category_deal') {
  const p = hintData.promo;
  const dt = discountText(p);
  if (dt) {
    if (p.discount_type === 'percentage') hint = 'Deal: ' + p.promo_code + ' - ' + p.discount_value + '% off on all ' + hintData.category + '!';
    else hint = 'Deal: ' + p.promo_code + ' - Rs.' + p.discount_value + ' off on ' + hintData.category + '!';
  } else {
    hint = 'Deal: ' + p.promo_code + ' applies to all ' + hintData.category + ' today!';
  }
}
else if (hintType === 'threshold_unlock') {
  const p = hintData.promo;
  const dt = discountText(p);
  if (dt) {
    hint = 'Add Rs.' + hintData.gap + ' more to unlock ' + dt + ' your entire order!';
  } else {
    hint = 'Add Rs.' + hintData.gap + ' more to unlock a special deal on your entire order!';
  }
}
else if (hintType === 'complementary') {
  const p = hintData.promo;
  const dt = discountText(p);
  if (dt) {
    hint = hintData.target_name + ' goes great with this! ' + p.promo_code + ' gives you ' + dt + ' on it today.';
  } else {
    hint = hintData.target_name + ' goes great with this — add it to your cart? \uD83D\uDED2';
  }
}
else if (hintType === 'history_reorder') {
  const p = hintData.promo;
  const dt = discountText(p);
  if (dt) {
    hint = "You\u2019ve ordered " + hintData.target_name + ' before \u2014 ' + dt + ' today! \uD83D\uDD01';
  } else {
    hint = "You\u2019ve ordered " + hintData.target_name + ' before \u2014 add it again? \uD83D\uDD01';
  }
}

return [{ json: { promo_hint: hint, promo_code_shown: hint ? best.promo_code : '' } }];

