=INSERT INTO public.promo_impressions (chat_id, promo_code) 
SELECT {{ $('Normalize Promo Input').first().json.chat_id }}, '{{ $json.promo_code_shown }}'
WHERE '{{ $json.promo_code_shown }}' != '';

parameters.jsCode:
const chatId = String($('Normalize Promo Input').first().json.chat_id || $('Start').first().json.tool_input?.chat_id || '');
const allPromos = $('Get All Active Promotions').all().map(i => i.json).filter(i => i && i.promo_code);

if (allPromos.length === 0) {
  return [{ json: {
    confirmation_message: "🎁 No active offers right now. Check back soon — deals are added daily!",
    chat_id: chatId,
    message_type: 'text',
    promo_hint: '',
    promo_code_shown: ''
  }}];
}

const lines = allPromos.map(p => {
  let disc = '';
  if (p.discount_type === 'percentage') disc = `${p.discount_value}% off`;
  else if (p.discount_type === 'flat') disc = `₹${p.discount_value} off`;
  else if (p.discount_type === 'bogo') disc = 'Buy 2 Get 1 Free';
  else disc = p.discount_type || 'Special deal';

  let scope = '';
  if (p.min_cart_value) scope = ` (min cart ₹${p.min_cart_value})`;

  let validity = '';
  if (p.valid_until) {
    const d = new Date(p.valid_until);
    validity = ` — valid till ${d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short' })}`;
  }

  const desc = p.description ? `\n   ${p.description}` : '';
  return `🏷 *${p.promo_code}* — ${disc}${scope}${validity}${desc}`;
}).join('\n\n');

// Also surface the best scored promo hint if available
const hint = $('Format Promo Hint').first().json;
const hintLine = hint && hint.promo_hint ? `\n\n💡 *Tip:* ${hint.promo_hint}` : '';

const msg = `🎉 *Today's Offers*\n\n${lines}${hintLine}\n\n_Discounts apply automatically at checkout!_`;

return [{ json: {
  confirmation_message: msg,
  chat_id: chatId,
  message_type: 'text',
  promo_hint: hint?.promo_hint || '',
  promo_code_shown: hint?.promo_code_shown || ''
}}];

const d = $json;
let ti = d.tool_input || {};
if (typeof ti === 'string') {
  try { ti = JSON.parse(ti); } catch(e) { ti = {}; }
}
const chatId = String(d.chat_id || ti.chat_id || '');
const sku = d.sku || ti.sku || '';
const cartTotal = parseFloat(d.cart_total || ti.cart_total || 0);
const userQuery = d.user_query || ti.user_query || '';
return [{ json: { chat_id: chatId, sku, cart_total: cartTotal, user_query: userQuery } }];

